require('dotenv').config();
const cloudinary = require('cloudinary').v2;
const fs = require('fs');
const path = require('path');

// Configure cloudinary
cloudinary.config({
  cloud_name: process.env.CLOUDINARY_CLOUD_NAME,
  api_key: process.env.CLOUDINARY_API_KEY,
  api_secret: process.env.CLOUDINARY_API_SECRET
});

async function testThumbnailUpload() {
  console.log('🔍 Testing Cloudinary thumbnail upload directly...');
  
  // Create a tiny test image (1x1 pixel JPG)
  const testImage = Buffer.from(
    '',
    'base64'
  );
  
  try {
    // Try upload with explicit format
    const result = await cloudinary.uploader.upload(
      `data:image/jpeg;base64,${testImage.toString('base64')}`,
      {
        folder: 'test-thumbnails',
        resource_type: 'image',
        format: 'jpg'  // Explicitly set format
      }
    );
    
    console.log('✅ Upload successful!');
    console.log('Result:', {
      publicId: result.public_id,
      format: result.format,
      url: result.secure_url
    });
    
    // Clean up
    await cloudinary.uploader.destroy(result.public_id);
    console.log('✅ Test image cleaned up');
    
  } catch (error) {
    console.error('❌ Upload failed:');
    console.error('Error message:', error.message);
    console.error('Error details:', error);
  }
}

testThumbnailUpload();